/**
 * The shape of the dot to be rendered for each data point in the series.
 * @public
 */
export type PointShapeType = 'circle' | 'diamond' | 'square' | 'triangle';
/** @public */
export type Variant = 'single' | 'multi' | 'bubble';
/** @public */
export type VariantShape = PointShapeType | Variant;
